import { describe, it, expect } from 'vitest';
import {
  estimateNoiseStd,
  estimateNoiseFloor,
} from '../src/image-noise-estimate';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function makeUniformNoisePlane(
  w: number,
  h: number,
  amplitude: number,
  base: number,
  seed: number,
): Float32Array {
  const rand = lcg(seed);
  const plane = new Float32Array(w * h);
  for (let i = 0; i < plane.length; i++) {
    plane[i] = base + amplitude * (rand() - 0.5);
  }
  return plane;
}

function makeGradientPlane(w: number, h: number): Float32Array {
  const plane = new Float32Array(w * h);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      plane[y * w + x] = x / (w - 1);
    }
  }
  return plane;
}

function addUniformNoise(
  plane: Float32Array,
  amplitude: number,
  seed: number,
): Float32Array {
  const rand = lcg(seed);
  const out = new Float32Array(plane.length);
  for (let i = 0; i < plane.length; i++) {
    out[i] = plane[i] + amplitude * (rand() - 0.5);
  }
  return out;
}

describe('estimateNoiseStd (Immerkaer 1996)', () => {
  it('recovers noise std from a pure uniform-noise plane', () => {
    // True std for uniform amplitude A is A / sqrt(12).
    const amp = 0.05;
    const trueSigma = amp / Math.sqrt(12); // ~0.01443
    const plane = makeUniformNoisePlane(64, 64, amp, 0.5, 0xC0FFEE);

    const sigma = estimateNoiseStd({ plane, width: 64, height: 64 });

    // Should land within +/- 50% of the true value.
    expect(sigma).toBeGreaterThan(trueSigma * 0.5);
    expect(sigma).toBeLessThan(trueSigma * 1.5);
  });

  it('returns ~0 for a noise-free smooth gradient', () => {
    const plane = makeGradientPlane(64, 64);
    const sigma = estimateNoiseStd({ plane, width: 64, height: 64 });
    expect(sigma).toBeLessThan(1e-3);
  });

  it('estimate scales roughly with noise amplitude on a gradient base', () => {
    const base = makeGradientPlane(64, 64);
    const noisy = addUniformNoise(base, 0.02, 0x1234);
    const baseSigma = estimateNoiseStd({
      plane: base,
      width: 64,
      height: 64,
    });
    const noisySigma = estimateNoiseStd({
      plane: noisy,
      width: 64,
      height: 64,
    });
    // Noise amplitude 0.02 -> uniform std ~0.00577. Should be much larger
    // than the gradient-only baseline.
    expect(noisySigma).toBeGreaterThan(baseSigma * 10);
    // And in the right ballpark of the true value (0.02/sqrt(12)).
    const trueSigma = 0.02 / Math.sqrt(12);
    expect(noisySigma).toBeGreaterThan(trueSigma * 0.5);
    expect(noisySigma).toBeLessThan(trueSigma * 1.5);
  });

  it('is monotonically increasing in noise amplitude', () => {
    const base = makeGradientPlane(64, 64);
    const sigmas: number[] = [];
    for (const amp of [0.01, 0.05, 0.10]) {
      const noisy = addUniformNoise(base, amp, 0xBEEF + Math.round(amp * 1000));
      sigmas.push(
        estimateNoiseStd({ plane: noisy, width: 64, height: 64 }),
      );
    }
    expect(sigmas[0]).toBeLessThan(sigmas[1]);
    expect(sigmas[1]).toBeLessThan(sigmas[2]);
  });
});

describe('estimateNoiseFloor', () => {
  it('returns ~sigma^2 for a noisy plane', () => {
    const plane = makeUniformNoisePlane(64, 64, 0.05, 0.5, 0xABCD);
    const sigma = estimateNoiseStd({ plane, width: 64, height: 64 });
    const floor = estimateNoiseFloor({ plane, width: 64, height: 64 });
    // Floor should equal sigma^2 (well above the 1e-5 floor for this noise).
    expect(floor).toBeGreaterThan(1e-5);
    expect(floor).toBeCloseTo(sigma * sigma, 10);
  });

  it('returns the 1e-5 floor for a noise-free smooth plane', () => {
    const plane = makeGradientPlane(64, 64);
    const floor = estimateNoiseFloor({ plane, width: 64, height: 64 });
    expect(floor).toBe(1e-5);
  });
});

describe('estimateNoiseStd validation', () => {
  it('throws RangeError when width < 3', () => {
    const plane = new Float32Array(2 * 4);
    expect(() =>
      estimateNoiseStd({ plane, width: 2, height: 4 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError when height < 3', () => {
    const plane = new Float32Array(4 * 2);
    expect(() =>
      estimateNoiseStd({ plane, width: 4, height: 2 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError when plane.length !== width*height', () => {
    const plane = new Float32Array(10); // mismatch
    expect(() =>
      estimateNoiseStd({ plane, width: 4, height: 4 }),
    ).toThrow(RangeError);
  });
});
